import{_ as a,a as t,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"د Google Drive Channel اضافه کول","description":"","frontmatter":{},"headers":[],"relativePath":"ps/upload/google-drive.md","filePath":"ps/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"ps/upload/google-drive.md"};function c(p,e,h,g,u,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="د-google-drive-channel-اضافه-کول" tabindex="-1">د Google Drive Channel اضافه کول <a class="header-anchor" href="#د-google-drive-channel-اضافه-کول" aria-label="Permalink to &quot;د Google Drive Channel اضافه کول&quot;">​</a></h1><h2 id="مخکې-څه-ته-اړتیا-لرئ" tabindex="-1">مخکې څه ته اړتیا لرئ <a class="header-anchor" href="#مخکې-څه-ته-اړتیا-لرئ" aria-label="Permalink to &quot;مخکې څه ته اړتیا لرئ&quot;">​</a></h2><p>له پیل مخکې دا شیان برابر کړئ:</p><table tabindex="0"><thead><tr><th>اړتیا</th><th>ولې ورته اړتیا ده</th></tr></thead><tbody><tr><td>Google account</td><td>Google Cloud ته د لاسرسي او Google Drive د authorize کولو لپاره</td></tr><tr><td>Google Cloud project</td><td>د Drive API فعالولو او OAuth credentials جوړولو لپاره</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed یې د <code>Client ID</code>، <code>Client Secret</code> او <code>Refresh Token</code> اخیستلو لپاره کاروي</td></tr><tr><td>ستاسو ImgBed domain</td><td>د OAuth redirect URI لپاره کارېږي. دا باید له هغه domain سره برابر وي چې تاسې یې رښتیا کاروئ.</td></tr></tbody></table><h2 id="د-تنظیم-پړاوونه" tabindex="-1">د تنظیم پړاوونه <a class="header-anchor" href="#د-تنظیم-پړاوونه" aria-label="Permalink to &quot;د تنظیم پړاوونه&quot;">​</a></h2><h3 id="_1-ګام-google-drive-api-فعال-کړئ" tabindex="-1">1 ګام: Google Drive API فعال کړئ <a class="header-anchor" href="#_1-ګام-google-drive-api-فعال-کړئ" aria-label="Permalink to &quot;1 ګام: Google Drive API فعال کړئ&quot;">​</a></h3><ol><li>Google Cloud Console پرانیزئ.</li><li>نوی project جوړ کړئ یا موجود project وټاکئ.</li><li><code>APIs &amp; Services</code> ته لاړ شئ.</li><li><code>Enable APIs and Services</code> کلیک کړئ.</li><li><code>Google Drive API</code> ولټوئ.</li><li>پاڼه یې پرانیزئ او enable کلیک کړئ.</li></ol><h3 id="_2-ګام-د-oauth-consent-screen-تنظیم-کړئ" tabindex="-1">2 ګام: د OAuth Consent Screen تنظیم کړئ <a class="header-anchor" href="#_2-ګام-د-oauth-consent-screen-تنظیم-کړئ" aria-label="Permalink to &quot;2 ګام: د OAuth Consent Screen تنظیم کړئ&quot;">​</a></h3><ol><li>په Google Cloud کې <code>Google Auth Platform</code> پرانیزئ.</li><li>د <code>Branding</code> بنسټیز معلومات بشپړ کړئ، لکه app name، support email او developer contact email.</li><li><code>Audience</code> پرانیزئ.</li><li>د ډېرو self-hosted شخصي نصبونو لپاره <code>External</code> مناسب دی.</li><li>که <code>External</code> مو وټاکه، هغه Google account چې authorize کوئ د <code>Test users</code> لاندې اضافه کړئ.</li><li><code>Data Access</code> پرانیزئ.</li><li>د Google Drive اړین permissions اضافه کړئ.</li></ol><h3 id="_3-ګام-oauth-2-0-client-جوړ-کړئ" tabindex="-1">3 ګام: OAuth 2.0 Client جوړ کړئ <a class="header-anchor" href="#_3-ګام-oauth-2-0-client-جوړ-کړئ" aria-label="Permalink to &quot;3 ګام: OAuth 2.0 Client جوړ کړئ&quot;">​</a></h3><ol><li>په <code>Google Auth Platform</code> کې <code>Clients</code> پرانیزئ.</li><li>نوی client جوړ کړئ.</li><li>د application type په توګه <code>Web application</code> وټاکئ.</li><li>داسې نوم ورکړئ چې وروسته یې وپېژنئ.</li><li>د authorized JavaScript origins لپاره خپل ImgBed URL ولیکئ، د بېلګې په توګه:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>د authorized redirect URIs لپاره ولیکئ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+t+'" alt="Enter domain and callback URL" loading="lazy"></p><p>کله چې client جوړ شو، دا ارزښتونه copy کړئ:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="_4-ګام-د-google-drive-channel-ډک-کړئ" tabindex="-1">4 ګام: د Google Drive Channel ډک کړئ <a class="header-anchor" href="#_4-ګام-د-google-drive-channel-ډک-کړئ" aria-label="Permalink to &quot;4 ګام: د Google Drive Channel ډک کړئ&quot;">​</a></h2><p>په Upload Settings کې <code>Google Drive</code> وټاکئ او دا fields ډک کړئ:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>څه ولیکئ</th></tr></thead><tbody><tr><td>Channel name</td><td>داسې نوم چې وپېژندل شي، لکه <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>له Google Cloud څخه اخیستل شوی Client ID</td></tr><tr><td>Client Secret</td><td>له Google Cloud څخه اخیستل شوی Client Secret</td></tr><tr><td>Refresh Token</td><td>اوس یې تش پرېږدئ. په بل ګام کې یې اخلئ.</td></tr><tr><td>Root directory</td><td>اختیاري. Default یې <code>imgbed</code> دی.</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="_5-ګام-refresh-token-واخلئ" tabindex="-1">5 ګام: Refresh Token واخلئ <a class="header-anchor" href="#_5-ګام-refresh-token-واخلئ" aria-label="Permalink to &quot;5 ګام: Refresh Token واخلئ&quot;">​</a></h2><ol><li><code>Get Token</code> کلیک کړئ.</li><li>هغه Google account وټاکئ چې نښلول یې غواړئ.</li><li>د authorization پیغامونه بشپړ کړئ.</li><li>callback page به <code>Refresh Token</code> ښکاره کړي.</li><li>هغه copy کړئ.</li><li>بېرته ImgBed ته راشئ او د <code>Refresh Token</code> field کې یې paste کړئ.</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>که وروسته Google account بدل کړئ، OAuth client بدل کړئ، یا پخوانی authorization expire شي، channel ړنګولو ته اړتیا نشته. د edit پاڼه پرانیزئ او <code>Reauthorize</code> کلیک کړئ.</p><h2 id="_6-ګام-channel-خوندي-کړئ" tabindex="-1">6 ګام: Channel خوندي کړئ <a class="header-anchor" href="#_6-ګام-channel-خوندي-کړئ" aria-label="Permalink to &quot;6 ګام: Channel خوندي کړئ&quot;">​</a></h2><p>کله چې ټول fields ډک شول، channel save کړئ.</p><h2 id="چټک-بهیر" tabindex="-1">چټک بهیر <a class="header-anchor" href="#چټک-بهیر" aria-label="Permalink to &quot;چټک بهیر&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Google Cloud</span></span>
<span class="line"><span>-&gt; Create or select a project</span></span>
<span class="line"><span>-&gt; Enable Google Drive API</span></span>
<span class="line"><span>-&gt; Configure Google Auth Platform</span></span>
<span class="line"><span>-&gt; If Audience is External, add your Google account to Test users</span></span>
<span class="line"><span>-&gt; Create a Web application OAuth client</span></span>
<span class="line"><span>-&gt; Use https://your-domain.com/api/oauth/google/callback as the redirect URI</span></span>
<span class="line"><span>-&gt; Fill Client ID and Client Secret into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Sign in with Google and authorize</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span>
<span class="line"><span>-&gt; Upload a test image</span></span></code></pre></div><h2 id="ماخذونه" tabindex="-1">ماخذونه <a class="header-anchor" href="#ماخذونه" aria-label="Permalink to &quot;ماخذونه&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const C=i(d,[["render",c]]);export{f as __pageData,C as default};
